Spark https://zisen123.github.io/posts/css_colorful_button/ -<div class="highlight"><pre tabindex="0" style="color:#f8f8f2;background-color:#272822;-moz-tab-size:4;-o-tab-size:4;tab-size:4;-webkit-text-size-adjust:none;"><code class="language-html" data-lang="html"><span style="display:flex;"><span><span style="color:#75715e">&lt;!DOCTYPE html&gt;</span>
</span></span><span style="display:flex;"><span><span style="color:#75715e">&lt;!--from https://www.bilibili.com/video/BV1cK4y1k7qGs--&gt;</span>
</span></span><span style="display:flex;"><span>&lt;<span style="color:#f92672">html</span> <span style="color:#a6e22e">lang</span><span style="color:#f92672">=</span><span style="color:#e6db74">&#34;en&#34;</span>&gt;
</span></span><span style="display:flex;"><span>  &lt;<span style="color:#f92672">head</span>&gt;
</span></span><span style="display:flex;"><span>    &lt;<span style="color:#f92672">meta</span> <span style="color:#a6e22e">charset</span><span style="color:#f92672">=</span><span style="color:#e6db74">&#34;UTF-8&#34;</span>&gt;
</span></span><span style="display:flex;"><span>    &lt;<span style="color:#f92672">meta</span> <span style="color:#a6e22e">name</span><span style="color:#f92672">=</span><span style="color:#e6db74">&#34;viewport&#34;</span> <span style="color:#a6e22e">content</span><span style="color:#f92672">=</span><span style="color:#e6db74">&#34;width=divice-width, initial-scale=1.0&#34;</span>&gt;
</span></span><span style="display:flex;"><span>    &lt;<span style="color:#f92672">title</span>&gt;Colorful Button&lt;/<span style="color:#f92672">title</span>&gt;
</span></span><span style="display:flex;"><span>  &lt;/<span style="color:#f92672">head</span>&gt;
</span></span><span style="display:flex;"><span>  &lt;<span style="color:#f92672">body</span>&gt;
</span></span><span style="display:flex;"><span>    &lt;<span style="color:#f92672">a</span> <span style="color:#a6e22e">href</span><span style="color:#f92672">=</span><span style="color:#e6db74">&#34;javascript:;&#34;</span>&gt;Colorful Button&lt;/<span style="color:#f92672">a</span>&gt;
</span></span><span style="display:flex;"><span>  &lt;/<span style="color:#f92672">body</span>&gt;
</span></span><span style="display:flex;"><span>  &lt;<span style="color:#f92672">style</span>&gt;
</span></span><span style="display:flex;"><span>    <span style="color:#f92672">*</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">margin</span>: <span style="color:#ae81ff">0</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">padding</span>: <span style="color:#ae81ff">0</span>;
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>    <span style="color:#f92672">body</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">background</span>: <span style="color:#ae81ff">#000</span>;
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>    <span style="color:#f92672">a</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">text-decoration</span>: <span style="color:#66d9ef">none</span>;<span style="color:#75715e">/*why set text-decoration as none?*/</span>
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">position</span>:<span style="color:#66d9ef">absolute</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">top</span>: <span style="color:#ae81ff">50</span><span style="color:#66d9ef">%</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">left</span>: <span style="color:#ae81ff">50</span><span style="color:#66d9ef">%</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">transform</span>: translate(<span style="color:#ae81ff">-50</span><span style="color:#66d9ef">%</span>, <span style="color:#ae81ff">-50</span><span style="color:#66d9ef">%</span>);<span style="color:#75715e">/*translate the button self*/</span>
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">font-size</span>: <span style="color:#ae81ff">24</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">background</span>: linear-gradient(<span style="color:#ae81ff">90</span><span style="color:#66d9ef">deg</span>, <span style="color:#ae81ff">#03a9f4</span>, <span style="color:#ae81ff">#f441a5</span>, <span style="color:#ae81ff">#ffeb3b</span>, <span style="color:#ae81ff">#03a9f4</span>);
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">background-size</span>: <span style="color:#ae81ff">400</span><span style="color:#66d9ef">%</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">width</span>: <span style="color:#ae81ff">400</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">height</span>: <span style="color:#ae81ff">100</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">line-height</span>: <span style="color:#ae81ff">100</span><span style="color:#66d9ef">px</span>;<span style="color:#75715e">/*this means the height the text self */</span>
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">text-align</span>: <span style="color:#66d9ef">center</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">color</span>: <span style="color:#ae81ff">#fff</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">text-transform</span>: <span style="color:#66d9ef">capitalize</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">border-radius</span>: <span style="color:#ae81ff">50</span><span style="color:#66d9ef">px</span>;<span style="color:#75715e">/*make the profile round*/</span>
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">z-index</span>: <span style="color:#ae81ff">1</span>;
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>    <span style="color:#f92672">a</span>::<span style="color:#a6e22e">before</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">content</span>: <span style="color:#e6db74">&#34;&#34;</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">position</span>: <span style="color:#66d9ef">absolute</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">left</span>: <span style="color:#ae81ff">-5</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">top</span>: <span style="color:#ae81ff">-5</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">right</span>: <span style="color:#ae81ff">-5</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">bottom</span>: <span style="color:#ae81ff">-5</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">background</span>: linear-gradient(<span style="color:#ae81ff">90</span><span style="color:#66d9ef">deg</span>, <span style="color:#ae81ff">#03a9f4</span>, <span style="color:#ae81ff">#f441a5</span>, <span style="color:#ae81ff">#ffeb3b</span>, <span style="color:#ae81ff">#03a9f4</span>);
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">background-size</span>: <span style="color:#ae81ff">400</span><span style="color:#66d9ef">%</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">border-radius</span>: <span style="color:#ae81ff">50</span><span style="color:#66d9ef">px</span>;
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">filter</span>: blur(<span style="color:#ae81ff">20</span><span style="color:#66d9ef">px</span>);
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">z-index</span>: <span style="color:#ae81ff">-1</span>;
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>    <span style="color:#f92672">a</span>:<span style="color:#a6e22e">hover</span>::<span style="color:#a6e22e">before</span><span style="color:#f92672">,</span> <span style="color:#f92672">a</span>:<span style="color:#a6e22e">hover</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#66d9ef">animation</span>: sun <span style="color:#ae81ff">8</span><span style="color:#66d9ef">s</span> <span style="color:#66d9ef">infinite</span>;
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>    @<span style="color:#66d9ef">keyframes</span> <span style="color:#f92672">sun</span>{
</span></span><span style="display:flex;"><span>      <span style="color:#f92672">100</span><span style="color:#f92672">%</span>{
</span></span><span style="display:flex;"><span>          <span style="color:#66d9ef">background-position</span>: <span style="color:#ae81ff">-400</span><span style="color:#66d9ef">%</span> <span style="color:#ae81ff">0</span>;
</span></span><span style="display:flex;"><span>      }
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>  &lt;/<span style="color:#f92672">style</span>&gt;
</span></span><span style="display:flex;"><span>&lt;/<span style="color:#f92672">html</span>&gt;
</span></span></code></pre></div><h2 id="link"><a href="%5Bhttps://github.com/zisen123/CSS-leaner/blob/master/CSS%20Colorful%20Button/Colorful%20Button.html%5D(https://github.com/zisen123/CSS-leaner/blob/master/CSS%20Colorful%20Button/Colorful%20Button.html)">link</a></h2>
